    static void Main(string[] args)
    {
        // Initialize the grid
        char[,] grid = new char[16, 16];

        // Read the input
        for (int i = 0; i < 16; i++)
        {
            string line = Console.ReadLine();
            for (int j = 0; j < 16; j++)
            {
                grid[i, j] = line[j];
            }
        }

        // Perform the tests
        for (int i = 0; i < 16; i++)
        {
            for (int j = 0; j < 16; j++)
            {
                Console.Write(grid[i, j]);

                if (grid[i, j] != '#')
                {
                    int count = 0;

                    // Count the number of '#' around the current cell
                    for (int dx = -1; dx <= 1; dx++)
                    {
                        for (int dy = -1; dy <= 1; dy++)
                        {
                            int ni = i + dx;
                            int nj = j + dy;

                            if (ni >= 0 && ni < 16 && nj >= 0 && nj < 16 && grid[ni, nj] == '#')
                            {
                                count++;
                            }
                        }
                    }

                    // Print the count
                    Console.Write(count);
                }
            }

            Console.WriteLine();
        }
    }
}
