using System;

class Program
{
    static void Main(string[] args)
    {
        string input = Console.ReadLine();

        // Convert the input string to a character array
        char[] chars = input.ToCharArray();

        // Iterate through the character array
        for (int i = 0; i < chars.Length; i++)
        {
            // Check if the character is a lowercase letter (a-z)
            if (chars[i] >= 'a' && chars[i] <= 'z')
            {
                // Calculate the offset from 'a' to make the conversion
                int offset = chars[i] - 'a';

                // Convert the character by subtracting the offset
                chars[i] = (char)('z' - offset);
            }
        }

        // Convert the character array back to a string
        string output = new string(chars);

        Console.WriteLine(output);
    }
}
```

This code reads the input string, converts it to a character array, and then iterates through each character. If the character is a lowercase letter (between 'a' and 'z'), it calculates the offset from 'a' and converts the character to its reverse by subtracting the offset from 'z'. Finally, it converts the character array back to a string and prints the output.

